/* ── Model colors (colored by model, not category) ── */
const MODEL_COLOR = {
  "llava_next": "#6c5ce7",
  "mistral":    "#e17055",
  "qwen25vl":   "#00b894",
};
const MODEL_LABEL = {
  "llava_next": "LLaVA-Next",
  "mistral":    "Mistral",
  "qwen25vl":   "Qwen2.5-VL",
};
const MODEL_SHAPE = {
  "llava_next": "circle",
  "mistral":    "circle",
  "qwen25vl":   "circle",
};

/* ── State ── */
let _mode        = 'explore';
let _activeCat   = '';
let _compareSlots = [null, null];
let _activeSlot  = 0;
let _fuse        = null;
window._plotReady = false;

/* ── Helpers ── */
function hexToRgba(hex, a) {
  const r = parseInt(hex.slice(1,3),16);
  const g = parseInt(hex.slice(3,5),16);
  const b = parseInt(hex.slice(5,7),16);
  return `rgba(${r},${g},${b},${a})`;
}

/* ══════════════════════════════════════════
   PLOT
══════════════════════════════════════════ */
function renderPlot() {
  const isDark = document.documentElement.getAttribute('data-theme') === 'dark';
  const bg = isDark ? '#0b0b0b' : '#f5f5f3';

  // Group by model — one trace per model
  const byModel = {};
  ALL_DATA.forEach((d, i) => {
    const m = d.model;
    if (!byModel[m]) byModel[m] = { x:[], y:[], text:[], idx:[] };
    byModel[m].x.push(d.coords[0]);
    byModel[m].y.push(d.coords[1]);
    byModel[m].text.push(`<b>${d.title}</b><br>${MODEL_LABEL[m]||m} · ${d.category}`);
    byModel[m].idx.push(i);
  });

  const traces = Object.entries(byModel).map(([mName, g]) => ({
    x: g.x, y: g.y,
    mode: 'markers',
    type: 'scatter',
    name: MODEL_LABEL[mName] || mName,
    text: g.text,
    customdata: g.idx,
    hoverinfo: 'text',
    marker: {
      size: 3,
      color: hexToRgba(MODEL_COLOR[mName] || '#999', 0.80),
      symbol: MODEL_SHAPE[mName] || 'circle',
      line: { width: 0.5, color: isDark ? 'rgba(255,255,255,0.08)' : 'rgba(0,0,0,0.1)' }
    },
    showlegend: true,
  }));

  const layout = {
    paper_bgcolor: bg, plot_bgcolor: bg,
    margin: { t: 10, l: 10, r: 10, b: 10 },
    xaxis: { visible: false, zeroline: false },
    yaxis: { visible: false, zeroline: false },
    hovermode: 'closest',
    dragmode: 'pan',
    showlegend: true,
    legend: {
      x: 0.99, xanchor: 'right', y: 0.01, yanchor: 'bottom',
      bgcolor: isDark ? 'rgba(17,17,17,0.88)' : 'rgba(255,255,255,0.88)',
      bordercolor: isDark ? '#2a2a2a' : '#e0e0de',
      borderwidth: 1,
      font: { size: 10, color: isDark ? '#999' : '#555' },
      itemsizing: 'constant',
    }
  };
  const config = { responsive: true, displayModeBar: false, scrollZoom: true };

  Plotly.newPlot('demoPlot', traces, layout, config);
  window._plotReady = true;

  document.getElementById('demoPlot').on('plotly_click', (data) => {
    if (!data.points.length) return;
    const idx = data.points[0].customdata;
    if (idx == null) return;
    const head = ALL_DATA[idx];
    if (_mode === 'explore') showExplore(head);
    else handleCompare(head);
  });
}

/* ── Filter (dim non-matching points) ── */
function applyFilter() {
  const searchVal = document.getElementById('demoSearch').value.trim();
  const catVal    = document.getElementById('demoCat').value;
  const plotEl    = document.getElementById('demoPlot');
  if (!plotEl || !plotEl.data) return;

  const isDark = document.documentElement.getAttribute('data-theme') === 'dark';
  const dimColor = isDark ? 'rgba(80,80,80,0.06)' : 'rgba(180,180,180,0.10)';

  let fuseSet = null;
  if (searchVal && _fuse) {
    const res = _fuse.search(searchVal);
    fuseSet = new Set(res.map(r => r.refIndex));
  }

  const allColors = plotEl.data.map(trace =>
    (trace.customdata || []).map(idx => {
      const d = ALL_DATA[idx];
      const matchSearch = !searchVal ||
        (fuseSet && fuseSet.has(idx)) ||
        (d.vocab && d.vocab.some(w => w.toLowerCase() === searchVal.toLowerCase()));
      const matchCat = !catVal || d.category === catVal;
      if (matchSearch && matchCat) {
        return hexToRgba(MODEL_COLOR[d.model] || '#999', 0.82);
      }
      return dimColor;
    })
  );

  Plotly.restyle('demoPlot', { 'marker.color': allColors });
}

/* ══════════════════════════════════════════
   SIDEBAR — EXPLORE
══════════════════════════════════════════ */
function showExplore(head) {
  document.getElementById('dsEmpty').style.display    = 'none';
  document.getElementById('ds-compare').style.display = 'none';
  document.getElementById('ds-explore').style.display = 'block';
  document.getElementById('demoHint').style.display   = 'block';

  document.getElementById('de-title').textContent = head.title || 'Untitled';
  document.getElementById('de-id').textContent    = head.id;
  document.getElementById('de-score').textContent = `Specialization score: ${head.score}`;
  document.getElementById('de-desc').textContent  = head.description || '—';

  document.getElementById('de-badges').innerHTML = `
    <span class="ds-badge">${head.category || '—'}</span>
    <span class="ds-badge ds-badge-gray">${MODEL_LABEL[head.model] || head.model}</span>
  `;

  const vEl = document.getElementById('de-vocab');
  vEl.innerHTML = '';
  (head.vocab || []).forEach(w => {
    const s = document.createElement('span');
    s.className = 'ds-vocab-tag';
    s.textContent = w;
    vEl.appendChild(s);
  });
}

/* ══════════════════════════════════════════
   COMPARE
══════════════════════════════════════════ */
function setMode(m) {
  _mode = m;
  document.getElementById('btnExplore').className = 'demo-mode-btn' + (m==='explore' ? ' active' : '');
  document.getElementById('btnCompare').className = 'demo-mode-btn' + (m==='compare' ? ' active' : '');
  document.getElementById('dsEmpty').style.display    = 'none';
  document.getElementById('ds-explore').style.display = m==='explore' ? 'block' : 'none';
  document.getElementById('ds-compare').style.display = m==='compare' ? 'block' : 'none';
  document.getElementById('demoHint').style.display   = 'block';
  if (m === 'compare') { _compareSlots = [null, null]; _activeSlot = 0; renderSlots(); }
}

function handleCompare(head) {
  _compareSlots[_activeSlot] = head;
  if (_activeSlot === 0 && !_compareSlots[1]) _activeSlot = 1;
  renderSlots();
}

function renderSlots() {
  [0, 1].forEach(i => {
    const el    = document.getElementById(`cslot-${i}`);
    const h     = _compareSlots[i];
    const color = i === 0 ? '#6c5ce7' : '#e17055';
    if (h) {
      el.innerHTML = `
        <div class="cs-id">${h.id}</div>
        <div class="cs-model">${MODEL_LABEL[h.model]||h.model}</div>
        <div class="cs-title">${h.title.length>38 ? h.title.substring(0,38)+'…' : h.title}</div>
      `;
      el.style.borderColor = color;
      el.style.borderStyle = 'solid';
      el.style.cursor = 'pointer';
      el.onclick = () => { _activeSlot = i; };
    } else {
      el.innerHTML = `<span style="color:var(--text3);font-size:0.75rem">Select ${i===0?'A':'B'}</span>`;
      el.style.borderColor = 'var(--border2)';
      el.style.borderStyle = 'dashed';
      el.style.cursor = 'default';
      el.onclick = null;
    }
  });

  const res = document.getElementById('compareResults');
  if (_compareSlots[0] && _compareSlots[1]) {
    res.style.display = 'flex';
    const h1 = _compareSlots[0], h2 = _compareSlots[1];

    // Euclidean (normalized)
    const dx = h1.coords[0] - h2.coords[0], dy = h1.coords[1] - h2.coords[1];
    const eu = Math.sqrt(dx*dx + dy*dy);
    const n1 = Math.sqrt(h1.coords[0]**2 + h1.coords[1]**2);
    const n2 = Math.sqrt(h2.coords[0]**2 + h2.coords[1]**2);
    document.getElementById('mc-euc').textContent = (n1+n2) > 0 ? (eu/(n1+n2)).toFixed(4) : '—';

    // Cosine on PCA
    let cos = 'N/A';
    if (h1.pca && h2.pca && h1.pca.length === h2.pca.length) {
      let dot=0, a=0, b=0;
      h1.pca.forEach((v,i) => { dot+=v*h2.pca[i]; a+=v*v; b+=h2.pca[i]**2; });
      const denom = Math.sqrt(a)*Math.sqrt(b);
      cos = denom > 0 ? (dot/denom).toFixed(4) : '0.0000';
    }
    document.getElementById('mc-cos').textContent = cos;

    // Jaccard
    const v1 = h1.vocab||[], v2 = h2.vocab||[];
    const common = v1.filter(w => v2.includes(w));
    const union  = new Set([...v1,...v2]).size;
    document.getElementById('mc-jac').textContent = union > 0 ? (common.length/union*100).toFixed(1)+'%' : '0%';

    const cEl = document.getElementById('mc-common');
    cEl.innerHTML = common.length > 0
      ? common.map(w => `<span class="ds-vocab-tag">${w}</span>`).join('')
      : '<span style="color:var(--text3);font-size:0.72rem">No common vocabulary</span>';
  } else {
    res.style.display = 'none';
  }
}

/* ══════════════════════════════════════════
   RESIZABLE SIDEBAR
══════════════════════════════════════════ */
function initResize() {
  const handle  = document.getElementById('demoDragHandle');
  const sidebar = document.getElementById('demoSidebar');
  let resizing  = false;
  handle.addEventListener('mousedown', e => {
    resizing = true; handle.classList.add('dragging'); e.preventDefault();
  });
  document.addEventListener('mousemove', e => {
    if (!resizing) return;
    const shell  = document.getElementById('demoShell');
    const newW   = shell.getBoundingClientRect().right - e.clientX;
    if (newW > 220 && newW < 480) {
      sidebar.style.width = newW + 'px';
      Plotly.Plots.resize('demoPlot');
    }
  });
  document.addEventListener('mouseup', () => {
    resizing = false; handle.classList.remove('dragging');
  });
}

/* ══════════════════════════════════════════
   INIT
══════════════════════════════════════════ */
function initDemo() {
  // Populate category dropdown
  const cats = [...new Set(ALL_DATA.map(d => d.category))].sort();
  const sel  = document.getElementById('demoCat');
  cats.forEach(c => {
    const o = document.createElement('option');
    o.value = c; o.textContent = c;
    sel.appendChild(o);
  });

  // Fuse search index
  _fuse = new Fuse(ALL_DATA, {
    keys: ['title','category','model','id'],
    threshold: 0.3,
    ignoreLocation: true,
  });

  // Events
  document.getElementById('demoSearch').addEventListener('input', applyFilter);
  document.getElementById('demoCat').addEventListener('change', applyFilter);

  // Render
  renderPlot();

  // Show controls, hide loading
  document.getElementById('demoLoading').style.display  = 'none';
  document.getElementById('demoControls').style.display = 'flex';
  document.getElementById('demoHint').style.display     = 'block';

  initResize();
}

/* Called from toggleTheme() in main script to re-render on theme switch */
function onThemeChange() {
  if (window._plotReady) renderPlot();
}